#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

__kernel void dynproc_kernel(
    int iteration,
    __global int* gpuWall,
    __global int* gpuSrc,
    __global int* gpuResults,
    int cols,
    int rows,
    int startStep,
    int border,
    int HALO,
    __local int* prev,
    __local int* result,
    __global int* outputBuffer)
{
    (void)rows;
    (void)HALO;
    (void)outputBuffer;

    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int local_size = (int)get_local_size(0);

    int small_block_cols = local_size - iteration * 2;
    int blkX = small_block_cols * bx - border;
    int blkXmax = blkX + local_size - 1;
    int xidx = blkX + tx;

    if (IN_RANGE(xidx, 0, cols - 1)) {
        prev[tx] = gpuSrc[xidx];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > (cols - 1)) ? (local_size - 1 - (blkXmax - (cols - 1))) : (local_size - 1);

    for (int i = 0; i < iteration; i++) {
        int isValid = 0;

        if (IN_RANGE(tx, i + 1, local_size - i - 2) && IN_RANGE(tx, validXmin, validXmax)) {
            isValid = 1;
            int left = prev[tx - 1];
            int up = prev[tx];
            int right = prev[tx + 1];
            int shortest = MIN(MIN(left, up), right);
            int index = cols * (startStep + i) + xidx;
            result[tx] = shortest + gpuWall[index];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (i == iteration - 1) {
            if (isValid) {
                gpuResults[xidx] = result[tx];
            }
        } else {
            if (isValid) {
                prev[tx] = result[tx];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }
    }
}
